#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Default)]
#[serde(rename_all = "snake_case")]
pub enum GitStorageMethod {
    PlatformApi,
    /// Store sessions as git objects on an orphan branch (no external API needed).
    Native,
    #[default]
    #[serde(other)]
    None,
}

fn default_publish_on() -> PublishMode {
    PublishMode::Manual
}
fn default_server_url() -> String {
    "https://opensession.io".to_string()
}
fn default_nickname() -> String {
    "user".to_string()
}
fn default_exclude_patterns() -> Vec<String> {
    vec!["*.env".into(), "*secret*".into(), "*credential*".into()]
}

// ── File I/O ────────────────────────────────────────────────────────────

pub fn config_dir() -> Result<PathBuf> {
    let home = std::env::var("HOME")
        .or_else(|_| std::env::var("USERPROFILE"))
        .context("Could not determine home directory")?;
    Ok(PathBuf::from(home).join(".config").join("opensession"))
}

/// Load daemon config from `~/.config/opensession/daemon.toml`.
pub fn load_daemon_config() -> DaemonConfig {
    let path = match config_dir() {
        Ok(d) => d.join("daemon.toml"),
        Err(_) => return DaemonConfig::default(),
    };
    if !path.exists() {
        return DaemonConfig::default();
    }
    std::fs::read_to_string(&path)
        .ok()
        .and_then(|s| toml::from_str(&s).ok())
        .unwrap_or_default()
}

/// Save daemon config to `~/.config/opensession/daemon.toml`.
pub fn save_daemon_config(config: &DaemonConfig) -> Result<()> {
    let dir = config_dir()?;
    std::fs::create_dir_all(&dir)?;
    let path = dir.join("daemon.toml");
    let content = toml::to_string_pretty(config).context("Failed to serialize config")?;
    std::fs::write(&path, content)
        .with_context(|| format!("Failed to write {}", path.display()))?;
    Ok(())
}

/// Returns true if the config needs initial setup (no API key set).
pub fn needs_setup(config: &DaemonConfig) -> bool {
    config.server.api_key.is_empty()
}

/// Get daemon PID from PID file, if it exists.
pub fn daemon_pid() -> Option<u32> {
    let pid_path = config_dir().ok()?.join("daemon.pid");
    let content = std::fs::read_to_string(pid_path).ok()?;
    content.trim().parse().ok()
}

// ── Setting fields enum ─────────────────────────────────────────────────

/// Identifies a single editable setting in the settings view.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SettingField {
    ServerUrl,
    ApiKey,
    TeamId,
    Nickname,
    AutoPublish,
    PublishMode,
    DebounceSecs,
    HealthCheckSecs,
    MaxRetries,
    WatchClaudeCode,
    WatchOpenCode,
    WatchGoose,
    WatchAider,
    WatchCursor,
    StripPaths,
    StripEnvVars,
}

/// A display item in the settings list. Headers are not selectable.
#[derive(Debug, Clone)]
pub enum SettingItem {
    Header(&'static str),
    Field {
        field: SettingField,
        label: &'static str,
    },
}

impl SettingItem {
    pub fn field(&self) -> Option<SettingField> {
        match self {
            Self::Header(_) => None,
            Self::Field { field, .. } => Some(*field),
        }
    }
}

/// The ordered list of items shown in the settings view.
pub const SETTINGS_LAYOUT: &[SettingItem] = &[
    SettingItem::Header("Server"),
    SettingItem::Field {
        field: SettingField::ServerUrl,
        label: "Server URL",
    },
    SettingItem::Field {
        field: SettingField::ApiKey,
        label: "API Key",
    },
    SettingItem::Field {
        field: SettingField::TeamId,
        label: "Team ID",
    },
    SettingItem::Header("Identity"),
    SettingItem::Field {
        field: SettingField::Nickname,
        label: "Nickname",
    },
    SettingItem::Header("Daemon"),
    SettingItem::Field {
        field: SettingField::AutoPublish,
        label: "Auto Publish",
    },
    SettingItem::Field {
        field: SettingField::PublishMode,
        label: "Publish Mode",
    },
    SettingItem::Field {
        field: SettingField::DebounceSecs,
        label: "Debounce (secs)",
    },
    SettingItem::Field {
        field: SettingField::HealthCheckSecs,
        label: "Health Check (secs)",
    },
    SettingItem::Field {
        field: SettingField::MaxRetries,
        label: "Max Retries",
    },
    SettingItem::Header("Watchers"),
    SettingItem::Field {
        field: SettingField::WatchClaudeCode,
        label: "Claude Code",
    },
    SettingItem::Field {
        field: SettingField::WatchOpenCode,
        label: "OpenCode",
    },
    SettingItem::Field {
        field: SettingField::WatchGoose,
        label: "Goose",
    },
    SettingItem::Field {
        field: SettingField::WatchAider,
        label: "Aider",
    },
    SettingItem::Field {
        field: SettingField::WatchCursor,
        label: "Cursor",
    },
    SettingItem::Header("Privacy"),
    SettingItem::Field {
        field: SettingField::StripPaths,
        label: "Strip Paths",
    },
    SettingItem::Field {
        field: SettingField::StripEnvVars,
        label: "Strip Env Vars",
    },
];

impl SettingField {
    /// Whether this field is a boolean toggle.
    pub fn is_toggle(self) -> bool {
        matches!(
            self,
            Self::AutoPublish
                | Self::WatchClaudeCode
                | Self::WatchOpenCode
                | Self::WatchGoose
                | Self::WatchAider
                | Self::WatchCursor
                | Self::StripPaths
                | Self::StripEnvVars
        )
    }

    /// Whether this field cycles through enum options.
    pub fn is_enum(self) -> bool {
        matches!(self, Self::PublishMode)
    }

    /// Get the current value as a display string from the config.
    pub fn display_value(self, config: &DaemonConfig) -> String {
        match self {
            Self::ServerUrl => config.server.url.clone(),
            Self::ApiKey => {
                if config.server.api_key.is_empty() {
                    "(not set)".to_string()
                } else {
                    let key = &config.server.api_key;
                    let visible = key.len().min(8);
                    format!("{}...", &key[..visible])
                }
            }
            Self::TeamId => {
                if config.identity.team_id.is_empty() {
                    "(not set)".to_string()
                } else {
                    config.identity.team_id.clone()
                }
            }
            Self::Nickname => config.identity.nickname.clone(),
            Self::AutoPublish => on_off(config.daemon.auto_publish),
            Self::PublishMode => config.daemon.publish_on.display().to_string(),
            Self::DebounceSecs => config.daemon.debounce_secs.to_string(),
            Self::HealthCheckSecs => config.daemon.health_check_interval_secs.to_string(),
            Self::MaxRetries => config.daemon.max_retries.to_string(),
            Self::WatchClaudeCode => on_off(config.watchers.claude_code),
            Self::WatchOpenCode => on_off(config.watchers.opencode),
            Self::WatchGoose => on_off(config.watchers.goose),
            Self::WatchAider => on_off(config.watchers.aider),
            Self::WatchCursor => on_off(config.watchers.cursor),
            Self::StripPaths => on_off(config.privacy.strip_paths),
            Self::StripEnvVars => on_off(config.privacy.strip_env_vars),
        }
    }

    /// Get the raw (editable) value from the config.
    pub fn raw_value(self, config: &DaemonConfig) -> String {
        match self {
            Self::ServerUrl => config.server.url.clone(),
            Self::ApiKey => config.server.api_key.clone(),
            Self::TeamId => config.identity.team_id.clone(),
            Self::Nickname => config.identity.nickname.clone(),
            Self::DebounceSecs => config.daemon.debounce_secs.to_string(),
            Self::HealthCheckSecs => config.daemon.health_check_interval_secs.to_string(),
            Self::MaxRetries => config.daemon.max_retries.to_string(),
            _ => String::new(),
        }
    }

    /// Toggle a boolean field in the config.
    pub fn toggle(self, config: &mut DaemonConfig) {
        match self {
            Self::AutoPublish => config.daemon.auto_publish = !config.daemon.auto_publish,
            Self::WatchClaudeCode => config.watchers.claude_code = !config.watchers.claude_code,
            Self::WatchOpenCode => config.watchers.opencode = !config.watchers.opencode,
            Self::WatchGoose => config.watchers.goose = !config.watchers.goose,
            Self::WatchAider => config.watchers.aider = !config.watchers.aider,
            Self::WatchCursor => config.watchers.cursor = !config.watchers.cursor,
            Self::StripPaths => config.privacy.strip_paths = !config.privacy.strip_paths,
            Self::StripEnvVars => config.privacy.strip_env_vars = !config.privacy.strip_env_vars,
            _ => {}
        }
    }

    /// Cycle an enum field.
    pub fn cycle_enum(self, config: &mut DaemonConfig) {
        if let Self::PublishMode = self {
            config.daemon.publish_on = config.daemon.publish_on.cycle();
        }
    }

    /// Set a text/number value.
    pub fn set_value(self, config: &mut DaemonConfig, value: &str) {
        match self {
            Self::ServerUrl => config.server.url = value.to_string(),
            Self::ApiKey => config.server.api_key = value.to_string(),
            Self::TeamId => config.identity.team_id = value.to_string(),
            Self::Nickname => config.identity.nickname = value.to_string(),
            Self::DebounceSecs => {
                if let Ok(v) = value.parse() {
                    config.daemon.debounce_secs = v;
                }
            }
            Self::HealthCheckSecs => {
                if let Ok(v) = value.parse() {
                    config.daemon.health_check_interval_secs = v;
                }
            }
            Self::MaxRetries => {
                if let Ok(v) = value.parse() {
                    config.daemon.max_retries = v;
                }
            }
            _ => {}
        }
    }
}

fn on_off(v: bool) -> String {
    if v {
        "ON".to_string()
    } else {
        "OFF".to_string()
    }
}

/// Count of selectable (non-header) fields in SETTINGS_LAYOUT.
pub fn selectable_field_count() -> usize {
    SETTINGS_LAYOUT
        .iter()
        .filter(|item| item.field().is_some())
        .count()
}

/// Get the nth selectable field.
pub fn nth_selectable_field(n: usize) -> Option<SettingField> {
    SETTINGS_LAYOUT
        .iter()
        .filter_map(|item| item.field())
        .nth(n)
}

mod app;
mod async_ops;
mod config;
mod platform_api_storage;
mod ui;
mod views;

use anyhow::Result;
use app::{App, ServerInfo, ServerStatus, StartupStatus, UploadPhase, View};
use crossterm::{
    event::{self, Event, KeyEventKind},
    terminal::{disable_raw_mode, enable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen},
    ExecutableCommand,
};
use opensession_local_db::git::extract_git_context;
use opensession_local_db::LocalDb;
use ratatui::prelude::*;
use std::io::stdout;
use std::path::PathBuf;
use std::sync::Arc;
use std::time::Duration;

fn main() -> Result<()> {
    let args: Vec<String> = std::env::args().collect();

    let sessions = if args.len() > 1 {
        // Load from explicit file paths
        load_from_paths(&args[1..])
    } else {
        // Auto-discover local sessions
        load_sessions()
    };

    let mut app = App::new(sessions);

    // ── Load full daemon config ──────────────────────────────────────
    let daemon_config = config::load_daemon_config();
    let config_exists = config::config_dir()
        .map(|d| d.join("daemon.toml").exists())
        .unwrap_or(false);

    // Build server info from daemon config
    app.server_info = build_server_info(&daemon_config);
    app.team_id = if daemon_config.identity.team_id.is_empty() {
        None
    } else {
        Some(daemon_config.identity.team_id.clone())
    };
    app.daemon_config = daemon_config;
    app.connection_ctx = App::derive_connection_ctx(&app.daemon_config);

    // ── Build startup status ─────────────────────────────────────────
    let mut status = StartupStatus {
        sessions_cached: 0,
        repos_detected: 0,
        daemon_pid: config::daemon_pid(),
        config_exists,
    };

    // ── Open local DB and cache sessions ─────────────────────────────
    if let Ok(db) = LocalDb::open() {
        let db = Arc::new(db);
        // Cache parsed sessions into the local DB
        cache_sessions_to_db(&db, &app.sessions);
        status.sessions_cached = app.sessions.len();
        // Load repo list for view cycling
        app.repos = db.list_repos().unwrap_or_default();
        status.repos_detected = app.repos.len();
        app.db = Some(db);
    }

    app.startup_status = status;

    // ── If config needs setup, start in Setup view ───────────────────
    if config::needs_setup(&app.daemon_config) {
        app.view = View::Setup;
        app.settings_index = 0;
    }

    // Health check deferred to first poll loop iteration (non-blocking startup)
    // app.server_info.status starts as Unknown

    // Terminal setup
    enable_raw_mode()?;
    stdout().execute(EnterAlternateScreen)?;
    let backend = CrosstermBackend::new(stdout());
    let mut terminal = Terminal::new(backend)?;

    // Main loop
    let result = run(&mut terminal, &mut app);

    // Restore terminal
    disable_raw_mode()?;
    stdout().execute(LeaveAlternateScreen)?;

    result
}

fn is_local_url(url: &str) -> bool {
    let lower = url.to_lowercase();
    lower.contains("localhost")
        || lower.contains("127.0.0.1")
        || lower.contains("192.168.")
        || lower.contains("10.")
        || lower.contains("172.16.")
}

fn build_server_info(config: &config::DaemonConfig) -> Option<ServerInfo> {
    if config.server.url.is_empty() {
        return None;
    }

    // Try to read last upload time from state.json (legacy)
    let home = std::env::var("HOME")
        .or_else(|_| std::env::var("USERPROFILE"))
        .unwrap_or_default();
    let state_path = PathBuf::from(&home)
        .join(".config")
        .join("opensession")
        .join("state.json");

    let last_upload = std::fs::read_to_string(&state_path)
        .ok()
        .and_then(|s| serde_json::from_str::<serde_json::Value>(&s).ok())
        .and_then(|v| {
            v.get("uploaded")?
                .as_object()?
                .values()
                .filter_map(|v| v.as_str().map(String::from))
                .max()
        });

    Some(ServerInfo {
        url: config.server.url.clone(),
        status: ServerStatus::Unknown,
        last_upload,
    })
}

async fn check_health(server_url: &str) -> ServerStatus {
    let client = match opensession_api_client::ApiClient::new(server_url, Duration::from_secs(1)) {
        Ok(c) => c,
        Err(_) => return ServerStatus::Offline,
    };
    match client.health().await {
        Ok(resp) => ServerStatus::Online(resp.version),
        Err(_) => ServerStatus::Offline,
    }
}

/// Cache parsed sessions into the local DB with git context.
/// Skips git extraction for sessions already in the DB (only updates stats).
fn cache_sessions_to_db(db: &LocalDb, sessions: &[opensession_core::trace::Session]) {
    let existing = db.existing_session_ids();

    for session in sessions {
        if existing.contains(&session.session_id) {
            // Already cached → only update stats (skip expensive git subprocess calls)
            let _ = db.update_session_stats(session);
            continue;
        }

        // New session → full insert with git context extraction
        let source = session.session_id.clone();
        let cwd = session
            .context
            .attributes
            .get("cwd")
            .or_else(|| session.context.attributes.get("working_directory"))
            .and_then(|v| v.as_str().map(String::from));
        let git = cwd.as_deref().map(extract_git_context).unwrap_or_default();

        let _ = db.upsert_local_session(session, &source, &git);
    }
}

fn run(terminal: &mut Terminal<CrosstermBackend<std::io::Stdout>>, app: &mut App) -> Result<()> {
    let rt = tokio::runtime::Runtime::new()?;

    loop {
        // ── Handle pending async command ─────────────────────────────
        if let Some(cmd) = app.pending_command.take() {
            let result = rt.block_on(async_ops::execute(cmd, &app.daemon_config));
            app.apply_command_result(result);
        }

        // ── Handle legacy upload popup async ops ─────────────────────
        // Login (triggered from Setup view)
        if app.login_state.loading {
            app.pending_command = Some(async_ops::AsyncCommand::Login {
                email: app.login_state.email.clone(),
                [REDACTED_CREDENTIAL]
            });
        }

        // Fetch teams for upload popup
        if let Some(ref popup) = app.upload_popup {
            if matches!(popup.phase, UploadPhase::FetchingTeams) {
                app.pending_command = Some(async_ops::AsyncCommand::FetchUploadTeams);
            }
        }

        // Upload session
        if let Some(ref popup) = app.upload_popup {
            if matches!(popup.phase, UploadPhase::Uploading) {
                let team_id = popup.teams.get(popup.selected).and_then(|t| {
                    if t.is_personal {
                        None
                    } else {
                        Some(t.id.clone())
                    }
                });

                let session_clone = app.selected_session().cloned();

                if let Some(session) = session_clone {
                    let is_personal = popup
                        .teams
                        .get(popup.selected)
                        .map(|t| t.is_personal)
                        .unwrap_or(false);

                    // For personal sessions, try git storage
                    let body_url = if is_personal {
                        try_git_store(&session, &app.daemon_config)
                    } else {
                        None
                    };

                    let session_json = serde_json::to_value(&session).ok();
                    if let Some(json) = session_json {
                        app.pending_command = Some(async_ops::AsyncCommand::UploadSession {
                            session_json: json,
                            team_id,
                            body_url,
                        });
                    }
                } else if let Some(ref mut popup) = app.upload_popup {
                    popup.status = Some("No session selected".to_string());
                    popup.phase = UploadPhase::Done;
                }
            }
        }

        // Process any command generated above
        if let Some(cmd) = app.pending_command.take() {
            let result = rt.block_on(async_ops::execute(cmd, &app.daemon_config));
            app.apply_command_result(result);
        }

        terminal.draw(|frame| ui::render(frame, app))?;

        // ── Deferred health check (runs once, after first render) ────
        if !app.health_check_done {
            app.health_check_done = true;
            if let Some(ref mut info) = app.server_info {
                if is_local_url(&info.url) {
                    let url = info.url.clone();
                    info.status = rt.block_on(check_health(&url));
                }
            }
        }

        if event::poll(Duration::from_millis(100))? {
            if let Event::Key(key) = event::read()? {
                if key.kind != KeyEventKind::Press {
                    continue;
                }
                if app.handle_key(key.code) {
                    break;
                }
            }
        }
    }
    Ok(())
}

/// Try to store a session via platform API and return the body_url.
///
/// NOTE: This uses `reqwest::blocking` which must NOT be called inside
/// `tokio::Runtime::block_on()`. Currently safe because `try_git_store`
/// is called before the `rt.block_on(upload_session(...))` call.
fn try_git_store(
    session: &opensession_core::trace::Session,
    config: &config::DaemonConfig,
) -> Option<String> {
    if !matches!(
        config.git_storage.method,
        config::GitStorageMethod::PlatformApi
    ) {
        return None;
    }

    if config.git_storage.token.is_empty() {
        return None;
    }

    // Get working directory from session context
    let cwd = session
        .context
        .attributes
        .get("cwd")
        .or_else(|| session.context.attributes.get("working_directory"))
        .and_then(|v| v.as_str())?;

    // Extract remote URL via git CLI
    let git_ctx = opensession_local_db::git::extract_git_context(cwd);
    let remote_url = git_ctx.remote?;

    let jsonl = session.to_jsonl().ok()?;

    let storage = platform_api_storage::PlatformApiStorage::new(config.git_storage.token.clone());
    match storage.store(&remote_url, &session.session_id, jsonl.as_bytes()) {
        Ok(url) => Some(url),
        Err(e) => {
            eprintln!("git storage: {e}");
            None
        }
    }
}

/// Load sessions from explicit file paths passed as CLI args.
fn load_from_paths(args: &[String]) -> Vec<opensession_core::trace::Session> {
    let parsers = opensession_parsers::all_parsers();
    let mut sessions = Vec::new();

    for arg in args {
        let path = PathBuf::from(arg);
        if !path.exists() {
            eprintln!("Warning: file not found: {}", path.display());
            continue;
        }
        if let Some(parser) = parsers.iter().find(|p| p.can_parse(&path)) {
            match parser.parse(&path) {
                Ok(session) => sessions.push(session),
                Err(e) => eprintln!("Warning: failed to parse {}: {}", path.display(), e),
            }
        } else {
            eprintln!("Warning: no parser for {}", path.display());
        }
    }

    sessions.sort_by(|a, b| b.context.created_at.cmp(&a.context.created_at));
    sessions
}

/// Auto-discover sessions from known local paths.
fn load_sessions() -> Vec<opensession_core::trace::Session> {
    let locations = opensession_parsers::discover::discover_sessions();
    let parsers = opensession_parsers::all_parsers();
    let mut sessions = Vec::new();

    for location in &locations {
        for path in &location.paths {
            // Skip subagent session files
            let path_str = path.to_string_lossy();
            if path_str.contains("/subagents/") || path_str.contains("\\subagents\\") {
                continue;
            }
            if let Some(fname) = path.file_name().and_then(|f| f.to_str()) {
                if fname.starts_with("agent-") {
                    continue;
                }
            }

            if let Some(parser) = parsers.iter().find(|p| p.can_parse(path)) {
                if let Ok(session) = parser.parse(path) {
                    // Skip empty sessions (0 events usually means parse was incomplete)
                    if session.stats.event_count > 0 {
                        sessions.push(session);
                    }
                }
            }
        }
    }

    sessions.sort_by(|a, b| b.context.created_at.cmp(&a.context.created_at));
    sessions
}

