use crate::app::ServerInfo;

fn render_upload_popup(frame: &mut Frame, app: &App) {
    let popup = match &app.upload_popup {
        Some(p) => p,
        None => return,
    };

    // Center the popup
    let area = frame.area();
    let popup_width = 50u16.min(area.width.saturating_sub(4));
    let popup_height = 12u16.min(area.height.saturating_sub(4));
    let x = (area.width.saturating_sub(popup_width)) / 2;
    let y = (area.height.saturating_sub(popup_height)) / 2;
    let popup_area = Rect::new(x, y, popup_width, popup_height);

    frame.render_widget(Clear, popup_area);

    let title = match &popup.phase {
        UploadPhase::FetchingTeams => " Fetching Teams... ",
        UploadPhase::SelectTeam => " Select Team ",
        UploadPhase::Uploading => " Uploading... ",
        UploadPhase::Done => " Upload Result ",
    };

    let block = Block::bordered()
        .title(title)
        .border_style(Style::new().fg(Color::Rgb(100, 180, 240)));
    let inner = block.inner(popup_area);
    frame.render_widget(block, popup_area);

    let mut lines = Vec::new();

    match &popup.phase {
        UploadPhase::FetchingTeams => {
            lines.push(Line::from(Span::styled(
                "  Loading...",
                Style::new().fg(Color::Rgb(100, 180, 240)),
            )));
        }
        UploadPhase::SelectTeam => {
            for (i, team) in popup.teams.iter().enumerate() {
                let is_selected = i == popup.selected;
                let pointer = if is_selected { ">" } else { " " };
                let style = if is_selected {
                    Style::new().fg(Color::White).bold()
                } else {
                    Style::new().fg(Color::Rgb(140, 145, 160))
                };
                lines.push(Line::from(Span::styled(
                    format!(" {} {}", pointer, team.name),
                    style,
                )));
            }
            lines.push(Line::raw(""));
            lines.push(Line::from(vec![
                Span::styled(" j/k ", Style::new().fg(Color::Rgb(140, 145, 160))),
                Span::styled("select  ", Style::new().fg(Color::DarkGray)),
                Span::styled("Enter ", Style::new().fg(Color::Rgb(140, 145, 160))),
                Span::styled("upload  ", Style::new().fg(Color::DarkGray)),
                Span::styled("Esc ", Style::new().fg(Color::Rgb(140, 145, 160))),
                Span::styled("cancel", Style::new().fg(Color::DarkGray)),
            ]));
        }
        UploadPhase::Uploading => {
            lines.push(Line::from(Span::styled(
                "  Uploading session...",
                Style::new().fg(Color::Rgb(100, 180, 240)),
            )));
        }
        UploadPhase::Done => {
            if let Some(ref status) = popup.status {
                let color = if status.starts_with("Error") {
                    Color::Rgb(220, 80, 80)
                } else {
                    Color::Rgb(80, 200, 120)
                };
                lines.push(Line::from(Span::styled(
                    format!("  {status}"),
                    Style::new().fg(color),
                )));
            }
            lines.push(Line::raw(""));
            lines.push(Line::from(Span::styled(
                "  Press any key to close",
                Style::new().fg(Color::DarkGray),
            )));
        }
    }

    let paragraph = Paragraph::new(lines);
    frame.render_widget(paragraph, inner);
}

fn build_server_status_spans(info: &ServerInfo) -> Vec<Span<'_>> {
    let mut spans = Vec::new();

    // Shorten URL for display
    let display_url = info
        .url
        .trim_start_matches("http://")
        .trim_start_matches("https://");

    match &info.status {
        ServerStatus::Online(version) => {
            spans.push(Span::styled(
                format!("{} ", display_url),
                Style::new().fg(Color::Rgb(140, 145, 160)),
            ));
            spans.push(Span::styled(
                format!("online v{} ", version),
                Style::new().fg(Color::Rgb(80, 200, 120)),
            ));
        }
        ServerStatus::Offline => {
            spans.push(Span::styled(
                format!("{} ", display_url),
                Style::new().fg(Color::Rgb(140, 145, 160)),
            ));
            spans.push(Span::styled(
                "offline ",
                Style::new().fg(Color::Rgb(220, 80, 80)),
            ));
        }
        ServerStatus::Unknown => {
            // Web target: show last upload time if available
            if let Some(ref time) = info.last_upload {
                // Show only date portion for brevity
                let display_time = if time.len() > 10 { &time[..10] } else { time };
                spans.push(Span::styled(
                    format!("last upload: {} ", display_time),
                    Style::new().fg(Color::DarkGray),
                ));
            }
        }
    }

    spans
}

use crate::app::{App, SettingsSection};
