use ratatui::widgets::{
    Block, Padding, Paragraph, Scrollbar, ScrollbarOrientation, ScrollbarState,
};

pub fn render(frame: &mut Frame, app: &App, area: Rect) {
    match app.settings_section {
        SettingsSection::Profile => render_profile(frame, app, area),
        SettingsSection::Account => render_account(frame, app, area),
        SettingsSection::DaemonConfig => render_daemon_config(frame, app, area),
    }
}

// ── Profile section (read-only) ──────────────────────────────────────────

fn render_profile(frame: &mut Frame, app: &App, area: Rect) {
    let block = Block::bordered()
        .border_style(Style::new().fg(Color::DarkGray))
        .padding(Padding::new(2, 2, 1, 1));
    let inner = block.inner(area);
    frame.render_widget(block, area);

    if app.profile_loading {
        let msg =
            Paragraph::new("Loading profile...").style(Style::new().fg(Color::Rgb(100, 180, 240)));
        frame.render_widget(msg, inner);
        return;
    }

    let mut lines = vec![
        Line::from(Span::styled(
            "── Profile ──",
            Style::new().fg(Color::Rgb(100, 180, 240)).bold(),
        )),
        Line::raw(""),
    ];

    if let Some(ref profile) = app.profile {
        let fields: Vec<(&str, String)> = vec![
            ("Nickname", profile.nickname.clone()),
            (
                "Email",
                profile.email.clone().unwrap_or_else(|| "-".to_string()),
            ),
            (
                "API Key",
                if profile.api_key.len() > 12 {
                    format!("{}...", &profile.api_key[..12])
                } else {
                    profile.api_key.clone()
                },
            ),
            (
                "OAuth",
                if profile.oauth_providers.is_empty() {
                    "None".to_string()
                } else {
                    profile
                        .oauth_providers
                        .iter()
                        .map(|p| p.display_name.as_str())
                        .collect::<Vec<_>>()
                        .join(", ")
                },
            ),
            (
                "GitHub",
                profile
                    .github_username
                    .clone()
                    .unwrap_or_else(|| "-".to_string()),
            ),
        ];

        for (label, value) in &fields {
            lines.push(Line::from(vec![
                Span::styled(
                    format!("  {:<16}", label),
                    Style::new().fg(Color::Rgb(140, 145, 160)),
                ),
                Span::styled(value.clone(), Style::new().fg(Color::White)),
            ]));
        }

        lines.push(Line::raw(""));
        lines.push(Line::from(Span::styled(
            "  (read-only — edit via web UI)",
            Style::new().fg(Color::Rgb(60, 65, 80)),
        )));
    } else {
        lines.push(Line::from(Span::styled(
            "  Not connected to server. Configure API key first.",
            Style::new().fg(Color::Rgb(140, 145, 160)),
        )));
    }

    let paragraph = Paragraph::new(lines);
    frame.render_widget(paragraph, inner);
}

// ── Account section (API key, password change) ───────────────────────────

fn render_account(frame: &mut Frame, app: &App, area: Rect) {
    let block = Block::bordered()
        .border_style(Style::new().fg(Color::DarkGray))
        .padding(Padding::new(2, 2, 1, 1));
    let inner = block.inner(area);
    frame.render_widget(block, area);

    let mut lines = vec![
        Line::from(Span::styled(
            "── API Key ──",
            Style::new().fg(Color::Rgb(100, 180, 240)).bold(),
        )),
        Line::raw(""),
    ];

    // Current API key (masked)
    let key_display = if app.daemon_config.server.api_key.is_empty() {
        "(not set)".to_string()
    } else {
        let key = &app.daemon_config.server.api_key;
        let visible = key.len().min(8);
        format!(
            "{}...{}",
            &key[..visible],
            &key[key.len().saturating_sub(4)..]
        )
    };

    lines.push(Line::from(vec![
        Span::styled(
            "  API Key:        ",
            Style::new().fg(Color::Rgb(140, 145, 160)),
        ),
        Span::styled(key_display, Style::new().fg(Color::White)),
    ]));
    lines.push(Line::from(Span::styled(
        "  Press 'r' to regenerate",
        Style::new().fg(Color::Rgb(60, 65, 80)),
    )));
    lines.push(Line::raw(""));

    // Password change form
    lines.push(Line::from(Span::styled(
        "── Change Password ──",
        Style::new().fg(Color::Rgb(100, 180, 240)).bold(),
    )));
    lines.push(Line::raw(""));

    let pw_fields = [
        (
            "Current Password",
            mask_password(&app.password_form.current),
        ),
        (
            "New Password",
            mask_password(&app.password_form.new_password),
        ),
        (
            "Confirm Password",
            mask_password(&app.password_form.confirm),
        ),
    ];

    for (i, (label, display)) in pw_fields.iter().enumerate() {
        let is_selected = app.settings_index == i;
        let is_editing = is_selected && app.password_form.editing;

        let pointer = if is_selected { ">" } else { " " };
        let pointer_style = if is_selected {
            Style::new().fg(Color::Cyan).bold()
        } else {
            Style::new().fg(Color::DarkGray)
        };

        let label_style = if is_selected {
            Style::new().fg(Color::White).bold()
        } else {
            Style::new().fg(Color::Rgb(140, 145, 160))
        };

        let value_text = if is_editing {
            format!("{}|", "*".repeat(app.edit_buffer.len()))
        } else if display.is_empty() {
            "(empty)".to_string()
        } else {
            display.to_string()
        };

        let value_style = if is_editing {
            Style::new().fg(Color::Rgb(220, 180, 60))
        } else {
            Style::new().fg(Color::Rgb(100, 105, 120))
        };

        let bg = if is_selected {
            Style::new().bg(Color::Rgb(30, 35, 50))
        } else {
            Style::new()
        };

        lines.push(
            Line::from(vec![
                Span::styled(format!(" {} ", pointer), pointer_style),
                Span::styled(format!("{:<22}", label), label_style),
                Span::styled(value_text, value_style),
            ])
            .style(bg),
        );
    }

    // Submit button
    let submit_selected = app.settings_index == 3;
    let submit_bg = if submit_selected {
        Style::new().bg(Color::Rgb(30, 35, 50))
    } else {
        Style::new()
    };
    let submit_style = if submit_selected {
        Style::new().fg(Color::Rgb(100, 180, 240)).bold()
    } else {
        Style::new().fg(Color::Rgb(60, 65, 80))
    };
    lines.push(Line::raw(""));
    lines.push(
        Line::from(vec![
            Span::styled(
                if submit_selected { " > " } else { "   " },
                if submit_selected {
                    Style::new().fg(Color::Cyan).bold()
                } else {
                    Style::new()
                },
            ),
            Span::styled("[Submit Password Change]", submit_style),
        ])
        .style(submit_bg),
    );

    let paragraph = Paragraph::new(lines);
    frame.render_widget(paragraph, inner);
}

fn mask_password(s: &str) -> String {
    if s.is_empty() {
        String::new()
    } else {
        "*".repeat(s.len())
    }
}

// ── DaemonConfig section (existing settings) ─────────────────────────────

fn render_daemon_config(frame: &mut Frame, app: &App, area: Rect) {
    let body_block = Block::bordered()
        .border_style(Style::new().fg(Color::DarkGray))
        .padding(Padding::new(1, 1, 0, 0));
    let inner = body_block.inner(area);
    frame.render_widget(body_block, area);

    let daemon_running = app.startup_status.daemon_pid.is_some();

    let mut lines = Vec::new();
    let mut selectable_idx: usize = 0;

    for item in SETTINGS_LAYOUT.iter() {
        match item {
            SettingItem::Header(title) => {
                if !lines.is_empty() {
                    lines.push(Line::raw(""));
                }

                // Check if this section should be grayed out when daemon is off
                let is_daemon_dependent = matches!(*title, "Daemon" | "Watchers");
                let header_style = if is_daemon_dependent && !daemon_running {
                    Style::new().fg(Color::Rgb(60, 65, 80))
                } else {
                    Style::new().fg(Color::Rgb(100, 180, 240)).bold()
                };

                let mut header_spans = vec![Span::styled(format!("── {} ──", title), header_style)];

                // Show daemon status warning
                if is_daemon_dependent && !daemon_running {
                    header_spans.push(Span::styled(
                        "  (daemon off)",
                        Style::new().fg(Color::Rgb(80, 85, 100)),
                    ));
                }

                lines.push(Line::from(header_spans));
                lines.push(Line::raw(""));
            }
            SettingItem::Field { field, label } => {
                let is_selected = selectable_idx == app.settings_index;
                let is_editing = is_selected && app.editing_field;

                // Determine if this field belongs to a daemon-dependent section
                let is_daemon_field = field.is_toggle()
                    && matches!(
                        field,
                        crate::config::SettingField::AutoPublish
                            | crate::config::SettingField::WatchClaudeCode
                            | crate::config::SettingField::WatchOpenCode
                            | crate::config::SettingField::WatchGoose
                            | crate::config::SettingField::WatchAider
                            | crate::config::SettingField::WatchCursor
                    )
                    || matches!(
                        field,
                        crate::config::SettingField::PublishMode
                            | crate::config::SettingField::DebounceSecs
                            | crate::config::SettingField::HealthCheckSecs
                            | crate::config::SettingField::MaxRetries
                    );
                let dimmed = is_daemon_field && !daemon_running;

                let pointer = if is_selected { ">" } else { " " };
                let pointer_style = if dimmed {
                    Style::new().fg(Color::Rgb(50, 55, 70))
                } else if is_selected {
                    Style::new().fg(Color::Cyan).bold()
                } else {
                    Style::new().fg(Color::DarkGray)
                };

                let label_style = if dimmed {
                    Style::new().fg(Color::Rgb(60, 65, 80))
                } else if is_selected {
                    Style::new().fg(Color::White).bold()
                } else {
                    Style::new().fg(Color::Rgb(140, 145, 160))
                };

                let value_text = if is_editing {
                    format!("{}|", app.edit_buffer)
                } else {
                    field.display_value(&app.daemon_config)
                };

                let value_style = if dimmed {
                    Style::new().fg(Color::Rgb(50, 55, 70))
                } else if is_editing {
                    Style::new().fg(Color::Rgb(220, 180, 60))
                } else if field.is_toggle() {
                    let on = matches!(field.display_value(&app.daemon_config).as_str(), "ON");
                    if on {
                        Style::new().fg(Color::Rgb(80, 200, 120))
                    } else {
                        Style::new().fg(Color::Rgb(220, 80, 80))
                    }
                } else if field.is_enum() {
                    Style::new().fg(Color::Rgb(180, 140, 220))
                } else if is_selected {
                    Style::new().fg(Color::White)
                } else {
                    Style::new().fg(Color::Rgb(100, 105, 120))
                };

                let bg = if is_selected {
                    Style::new().bg(Color::Rgb(30, 35, 50))
                } else {
                    Style::new()
                };

                // Type hint for editing
                let type_hint = if is_selected && !is_editing && !dimmed {
                    if field.is_toggle() {
                        Span::styled("  [Enter: toggle]", Style::new().fg(Color::Rgb(60, 65, 80)))
                    } else if field.is_enum() {
                        Span::styled("  [Enter: cycle]", Style::new().fg(Color::Rgb(60, 65, 80)))
                    } else {
                        Span::styled("  [Enter: edit]", Style::new().fg(Color::Rgb(60, 65, 80)))
                    }
                } else {
                    Span::raw("")
                };

                lines.push(
                    Line::from(vec![
                        Span::styled(format!(" {} ", pointer), pointer_style),
                        Span::styled(format!("{:<22}", label), label_style),
                        Span::styled(value_text, value_style),
                        type_hint,
                    ])
                    .style(bg),
                );

                selectable_idx += 1;
            }
        }
    }

    // Calculate scroll
    let visible_height = inner.height as usize;
    let current_line = find_selected_line(&lines, app.settings_index);
    let scroll = if current_line >= visible_height {
        current_line.saturating_sub(visible_height / 2)
    } else {
        0
    };

    let paragraph = Paragraph::new(lines.clone()).scroll((scroll as u16, 0));
    frame.render_widget(paragraph, inner);

    // Scrollbar
    let total_lines = lines.len();
    if total_lines > visible_height {
        let mut scrollbar_state = ScrollbarState::new(total_lines).position(scroll);
        let scrollbar = Scrollbar::new(ScrollbarOrientation::VerticalRight)
            .begin_symbol(None)
            .end_symbol(None)
            .thumb_style(Style::new().fg(Color::Rgb(80, 85, 100)));
        frame.render_stateful_widget(
            scrollbar,
            area.inner(Margin {
                vertical: 1,
                horizontal: 0,
            }),
            &mut scrollbar_state,
        );
    }
}

/// Find the approximate line index for the nth selectable field.
fn find_selected_line(lines: &[Line], selected_idx: usize) -> usize {
    let mut sel_count = 0usize;
    for (line_idx, line) in lines.iter().enumerate() {
        // A selectable line starts with " > " or "   " and has a label
        let text = line.to_string();
        if text.starts_with(" > ")
            || (text.starts_with("   ")
                && text.len() > 5
                && !text.trim().is_empty()
                && !text.contains("──"))
        {
            if sel_count == selected_idx {
                return line_idx;
            }
            sel_count += 1;
        }
    }
    0
}

