/// Kinds of modal overlay.
pub enum Modal {
    /// Confirmation dialog (e.g. remove member, regenerate key).
    Confirm {
        title: String,
        message: String,
        action: ConfirmAction,
    },
    /// Single-line text input (e.g. create team).
    TextInput {
        title: String,
        label: String,
        action: InputAction,
    },
}

/// What happens when a Confirm modal is accepted.
#[derive(Clone)]
pub enum ConfirmAction {
    RemoveMember { team_id: String, user_id: String },
    RegenerateApiKey,
    DeclineInvitation(String),
}

/// What happens when a TextInput modal is submitted.
#[derive(Clone)]
pub enum InputAction {
    CreateTeam,
}

/// Render the current modal overlay on top of everything.
pub fn render(frame: &mut Frame, modal: &Modal, edit_buffer: &str) {
    let area = frame.area();
    let popup_width = 50u16.min(area.width.saturating_sub(4));
    let popup_height = 10u16.min(area.height.saturating_sub(4));
    let x = (area.width.saturating_sub(popup_width)) / 2;
    let y = (area.height.saturating_sub(popup_height)) / 2;
    let popup_area = Rect::new(x, y, popup_width, popup_height);

    frame.render_widget(Clear, popup_area);

    match modal {
        Modal::Confirm { title, message, .. } => {
            let block = Block::bordered()
                .title(format!(" {} ", title))
                .border_style(Style::new().fg(Color::Rgb(220, 180, 60)));
            let inner = block.inner(popup_area);
            frame.render_widget(block, popup_area);

            let lines = vec![
                Line::raw(""),
                Line::from(Span::styled(
                    format!("  {}", message),
                    Style::new().fg(Color::White),
                )),
                Line::raw(""),
                Line::from(vec![
                    Span::styled("  y/Enter ", Style::new().fg(Color::Rgb(140, 145, 160))),
                    Span::styled("confirm  ", Style::new().fg(Color::DarkGray)),
                    Span::styled("n/Esc ", Style::new().fg(Color::Rgb(140, 145, 160))),
                    Span::styled("cancel", Style::new().fg(Color::DarkGray)),
                ]),
            ];
            let paragraph = Paragraph::new(lines);
            frame.render_widget(paragraph, inner);
        }
        Modal::TextInput { title, label, .. } => {
            let block = Block::bordered()
                .title(format!(" {} ", title))
                .border_style(Style::new().fg(Color::Rgb(100, 180, 240)));
            let inner = block.inner(popup_area);
            frame.render_widget(block, popup_area);

            let lines = vec![
                Line::raw(""),
                Line::from(vec![
                    Span::styled(format!("  {}: ", label), Style::new().fg(Color::White)),
                    Span::styled(
                        format!("{}|", edit_buffer),
                        Style::new().fg(Color::Rgb(220, 180, 60)),
                    ),
                ]),
                Line::raw(""),
                Line::from(vec![
                    Span::styled("  Enter ", Style::new().fg(Color::Rgb(140, 145, 160))),
                    Span::styled("submit  ", Style::new().fg(Color::DarkGray)),
                    Span::styled("Esc ", Style::new().fg(Color::Rgb(140, 145, 160))),
                    Span::styled("cancel", Style::new().fg(Color::DarkGray)),
                ]),
            ];
            let paragraph = Paragraph::new(lines);
            frame.render_widget(paragraph, inner);
        }
    }
}

