fn render_upload_popup(frame: &mut Frame, app: &App) {
    let popup = match &app.upload_popup {
        Some(p) => p,
        None => return,
    };

    // Center the popup
    let area = frame.area();
    let popup_width = 50u16.min(area.width.saturating_sub(4));
    let popup_height = 12u16.min(area.height.saturating_sub(4));
    let x = (area.width.saturating_sub(popup_width)) / 2;
    let y = (area.height.saturating_sub(popup_height)) / 2;
    let popup_area = Rect::new(x, y, popup_width, popup_height);

    frame.render_widget(Clear, popup_area);

    let title = match &popup.phase {
        UploadPhase::FetchingTeams => " Fetching Teams... ",
        UploadPhase::SelectTeam => " Select Team ",
        UploadPhase::Uploading => " Uploading... ",
        UploadPhase::Done => " Upload Result ",
    };

    let block = Block::bordered()
        .title(title)
        .border_style(Style::new().fg(Color::Rgb(100, 180, 240)));
    let inner = block.inner(popup_area);
    frame.render_widget(block, popup_area);

    let mut lines = Vec::new();

    match &popup.phase {
        UploadPhase::FetchingTeams => {
            lines.push(Line::from(Span::styled(
                "  Loading...",
                Style::new().fg(Color::Rgb(100, 180, 240)),
            )));
        }
        UploadPhase::SelectTeam => {
            for (i, team) in popup.teams.iter().enumerate() {
                let is_selected = i == popup.selected;
                let pointer = if is_selected { ">" } else { " " };
                let style = if is_selected {
                    Style::new().fg(Color::White).bold()
                } else {
                    Style::new().fg(Color::Rgb(140, 145, 160))
                };
                lines.push(Line::from(Span::styled(
                    format!(" {} {}", pointer, team.name),
                    style,
                )));
            }
            lines.push(Line::raw(""));
            lines.push(Line::from(vec![
                Span::styled(" j/k ", Style::new().fg(Color::Rgb(140, 145, 160))),
                Span::styled("select  ", Style::new().fg(Color::DarkGray)),
                Span::styled("Enter ", Style::new().fg(Color::Rgb(140, 145, 160))),
                Span::styled("upload  ", Style::new().fg(Color::DarkGray)),
                Span::styled("Esc ", Style::new().fg(Color::Rgb(140, 145, 160))),
                Span::styled("cancel", Style::new().fg(Color::DarkGray)),
            ]));
        }
        UploadPhase::Uploading => {
            lines.push(Line::from(Span::styled(
                "  Uploading session...",
                Style::new().fg(Color::Rgb(100, 180, 240)),
            )));
        }
        UploadPhase::Done => {
            if let Some(ref status) = popup.status {
                let color = if status.starts_with("Error") {
                    Color::Rgb(220, 80, 80)
                } else {
                    Color::Rgb(80, 200, 120)
                };
                lines.push(Line::from(Span::styled(
                    format!("  {status}"),
                    Style::new().fg(color),
                )));
            }
            lines.push(Line::raw(""));
            lines.push(Line::from(Span::styled(
                "  Press any key to close",
                Style::new().fg(Color::DarkGray),
            )));
        }
    }

    let paragraph = Paragraph::new(lines);
    frame.render_widget(paragraph, inner);
}

fn build_server_status_spans(info: &ServerInfo) -> Vec<Span<'_>> {
    let mut spans = Vec::new();

    // Shorten URL for display
    let display_url = info
        .url
        .trim_start_matches("http://")
        .trim_start_matches("https://");

    match &info.status {
        ServerStatus::Online(version) => {
            spans.push(Span::styled(
                format!("{} ", display_url),
                Style::new().fg(Color::Rgb(140, 145, 160)),
            ));
            spans.push(Span::styled(
                format!("online v{} ", version),
                Style::new().fg(Color::Rgb(80, 200, 120)),
            ));
        }
        ServerStatus::Offline => {
            spans.push(Span::styled(
                format!("{} ", display_url),
                Style::new().fg(Color::Rgb(140, 145, 160)),
            ));
            spans.push(Span::styled(
                "offline ",
                Style::new().fg(Color::Rgb(220, 80, 80)),
            ));
        }
        ServerStatus::Unknown => {
            // Web target: show last upload time if available
            if let Some(ref time) = info.last_upload {
                // Show only date portion for brevity
                let display_time = if time.len() > 10 { &time[..10] } else { time };
                spans.push(Span::styled(
                    format!("last upload: {} ", display_time),
                    Style::new().fg(Color::DarkGray),
                ));
            }
        }
    }

    spans
}

use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Top-level session - the root of a HAIL (Human AI Interaction Log) trace
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Session {
    /// Format version, e.g. "hail-1.0.0"
    pub version: String,
    /// Unique session identifier (UUID)
    pub session_id: String,
    /// AI agent information
    pub agent: Agent,
    /// Session metadata
    pub context: SessionContext,
    /// Flat timeline of events
    pub events: Vec<Event>,
    /// Aggregate statistics
    pub stats: Stats,
}

#[derive(Default)]
struct StatsAcc {
    message_count: u64,
    user_message_count: u64,
    tool_call_count: u64,
    task_ids: std::collections::HashSet<String>,
    total_input_tokens: u64,
    total_output_tokens: u64,
    changed_files: std::collections::HashSet<String>,
    lines_added: u64,
    lines_removed: u64,
}

impl StatsAcc {
    fn process(mut self, event: &Event) -> Self {
        match &event.event_type {
            EventType::UserMessage => {
                self.message_count += 1;
                self.user_message_count += 1;
            }
            EventType::AgentMessage => self.message_count += 1,
            EventType::ToolCall { .. }
            | EventType::FileRead { .. }
            | EventType::CodeSearch { .. }
            | EventType::FileSearch { .. } => self.tool_call_count += 1,
            EventType::FileEdit { path, diff } => {
                self.changed_files.insert(path.clone());
                if let Some(d) = diff {
                    for line in d.lines() {
                        if line.starts_with('+') && !line.starts_with("+++") {
                            self.lines_added += 1;
                        } else if line.starts_with('-') && !line.starts_with("---") {
                            self.lines_removed += 1;
                        }
                    }
                }
            }
            EventType::FileCreate { path } | EventType::FileDelete { path } => {
                self.changed_files.insert(path.clone());
            }
            _ => {}
        }
        if let Some(ref tid) = event.task_id {
            self.task_ids.insert(tid.clone());
        }
        if let Some(v) = event.attributes.get("input_tokens") {
            self.total_input_tokens += v.as_u64().unwrap_or(0);
        }
        if let Some(v) = event.attributes.get("output_tokens") {
            self.total_output_tokens += v.as_u64().unwrap_or(0);
        }
        self
    }

    fn into_stats(self, events: &[Event]) -> Stats {
        let duration_seconds = if let (Some(first), Some(last)) = (events.first(), events.last()) {
            (last.timestamp - first.timestamp).num_seconds().max(0) as u64
        } else {
            0
        };

        Stats {
            event_count: events.len() as u64,
            message_count: self.message_count,
            tool_call_count: self.tool_call_count,
            task_count: self.task_ids.len() as u64,
            duration_seconds,
            total_input_tokens: self.total_input_tokens,
            total_output_tokens: self.total_output_tokens,
            user_message_count: self.user_message_count,
            files_changed: self.changed_files.len() as u64,
            lines_added: self.lines_added,
            lines_removed: self.lines_removed,
        }
    }
}

impl Session {
    pub const CURRENT_VERSION: &'static str = "hail-1.0.0";

    pub fn new(session_id: String, agent: Agent) -> Self {
        Self {
            version: Self::CURRENT_VERSION.to_string(),
            session_id,
            agent,
            context: SessionContext::default(),
            events: Vec::new(),
            stats: Stats::default(),
        }
    }

    /// Serialize to HAIL JSONL string
    pub fn to_jsonl(&self) -> Result<String, crate::jsonl::JsonlError> {
        crate::jsonl::to_jsonl_string(self)
    }

    /// Deserialize from HAIL JSONL string
    pub fn from_jsonl(s: &str) -> Result<Self, crate::jsonl::JsonlError> {
        crate::jsonl::from_jsonl_str(s)
    }

    /// Recompute stats from events
    pub fn recompute_stats(&mut self) {
        let acc = self
            .events
            .iter()
            .fold(StatsAcc::default(), StatsAcc::process);
        self.stats = acc.into_stats(&self.events);
    }
}

/// AI agent information
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Agent {
    /// Provider: "anthropic", "openai", "local"
    pub provider: String,
    /// Model: "claude-opus-4-6", "gpt-4o"
    pub model: String,
    /// Tool: "claude-code", "cursor", "goose"
    pub tool: String,
    /// Tool version
    #[serde(skip_serializing_if = "Option::is_none")]
    pub tool_version: Option<String>,
}

/// Session context metadata
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SessionContext {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub title: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub description: Option<String>,
    #[serde(default)]
    pub tags: Vec<String>,
    pub created_at: DateTime<Utc>,
    pub updated_at: DateTime<Utc>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub related_session_ids: Vec<String>,
    #[serde(default, skip_serializing_if = "HashMap::is_empty")]
    pub attributes: HashMap<String, serde_json::Value>,
}

impl Default for SessionContext {
    fn default() -> Self {
        let now = Utc::now();
        Self {
            title: None,
            description: None,
            tags: Vec::new(),
            created_at: now,
            updated_at: now,
            related_session_ids: Vec::new(),
            attributes: HashMap::new(),
        }
    }
}

/// A single event in the flat timeline
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Event {
    /// Unique event identifier
    pub event_id: String,
    /// When this event occurred
    pub timestamp: DateTime<Utc>,
    /// Type of event
    pub event_type: EventType,
    /// Optional task grouping ID
    #[serde(skip_serializing_if = "Option::is_none")]
    pub task_id: Option<String>,
    /// Multimodal content
    pub content: Content,
    /// Duration in milliseconds (for tool calls, etc.)
    #[serde(skip_serializing_if = "Option::is_none")]
    pub duration_ms: Option<u64>,
    /// Arbitrary metadata
    #[serde(default, skip_serializing_if = "HashMap::is_empty")]
    pub attributes: HashMap<String, serde_json::Value>,
}

/// Event type - the core abstraction
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "type", content = "data")]
#[non_exhaustive]
pub enum EventType {
    // Conversation
    UserMessage,
    AgentMessage,
    SystemMessage,

    // AI internals
    Thinking,

    // Tools/Actions
    ToolCall {
        name: String,
    },
    ToolResult {
        name: String,
        is_error: bool,
        #[serde(skip_serializing_if = "Option::is_none")]
        call_id: Option<String>,
    },
    FileRead {
        path: String,
    },
    CodeSearch {
        query: String,
    },
    FileSearch {
        pattern: String,
    },
    FileEdit {
        path: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        diff: Option<String>,
    },
    FileCreate {
        path: String,
    },
    FileDelete {
        path: String,
    },
    ShellCommand {
        command: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        exit_code: Option<i32>,
    },

    // Multimodal generation
    ImageGenerate {
        prompt: String,
    },
    VideoGenerate {
        prompt: String,
    },
    AudioGenerate {
        prompt: String,
    },

    // Search/Reference
    WebSearch {
        query: String,
    },
    WebFetch {
        url: String,
    },

    // Task boundary markers (optional)
    TaskStart {
        #[serde(skip_serializing_if = "Option::is_none")]
        title: Option<String>,
    },
    TaskEnd {
        #[serde(skip_serializing_if = "Option::is_none")]
        summary: Option<String>,
    },

    // Extension point
    Custom {
        kind: String,
    },
}

/// Multimodal content container
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Content {
    pub blocks: Vec<ContentBlock>,
}

impl Content {
    pub fn empty() -> Self {
        Self { blocks: Vec::new() }
    }

    pub fn text(text: impl Into<String>) -> Self {
        Self {
            blocks: vec![ContentBlock::Text { text: text.into() }],
        }
    }

    pub fn code(code: impl Into<String>, language: Option<String>) -> Self {
        Self {
            blocks: vec![ContentBlock::Code {
                code: code.into(),
                language,
                start_line: None,
            }],
        }
    }
}

/// Individual content block
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "type")]
#[non_exhaustive]
pub enum ContentBlock {
    Text {
        text: String,
    },
    Code {
        code: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        language: Option<String>,
        #[serde(skip_serializing_if = "Option::is_none")]
        start_line: Option<u32>,
    },
    Image {
        url: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        alt: Option<String>,
        mime: String,
    },
    Video {
        url: String,
        mime: String,
    },
    Audio {
        url: String,
        mime: String,
    },
    File {
        path: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        content: Option<String>,
    },
    Json {
        data: serde_json::Value,
    },
    Reference {
        uri: String,
        media_type: String,
    },
}

/// Aggregate session statistics
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct Stats {
    pub event_count: u64,
    pub message_count: u64,
    pub tool_call_count: u64,
    pub task_count: u64,
    pub duration_seconds: u64,
    #[serde(default)]
    pub total_input_tokens: u64,
    #[serde(default)]
    pub total_output_tokens: u64,
    #[serde(default)]
    pub user_message_count: u64,
    #[serde(default)]
    pub files_changed: u64,
    #[serde(default)]
    pub lines_added: u64,
    #[serde(default)]
    pub lines_removed: u64,
}

