                            let tags = s.context.tags.join(" ").to_lowercase();

                            title.contains(&query)
                                || tool.contains(&query)
                                || model.contains(&query)
                                || sid.contains(&query)
                                || tags.contains(&query)
                        })
                        .map(|(i, _)| i)
                        .collect();
                }

                if self.filtered_sessions.is_empty() {
                    self.list_state.select(None);
                } else {
                    self.list_state.select(Some(0));
                }
            }
            ViewMode::Team(tid) => {
                if let Some(ref db) = self.db {
