        .block(
            Block::bordered()
                .title(format!(
                    " Timeline ({}/{}) ",
                    current_idx + 1,
                    total_visible
                ))
                .border_style(Style::new().fg(Color::Rgb(60, 65, 80))),
        )
        .wrap(Wrap { trim: false })
        .scroll((scroll as u16, 0));

    frame.render_widget(timeline, timeline_area);

    // Scrollbar
    let total_lines = lines.len();
    if total_lines > visible_height {
        let mut scrollbar_state = ScrollbarState::new(total_lines).position(scroll);
        let scrollbar = Scrollbar::new(ScrollbarOrientation::VerticalRight)
            .begin_symbol(None)
            .end_symbol(None)
            .thumb_style(Style::new().fg(Color::Rgb(80, 85, 100)));
        frame.render_stateful_widget(
            scrollbar,
            timeline_area.inner(Margin {
                vertical: 1,
                horizontal: 0,
            }),
            &mut scrollbar_state,
        );
    }
}

fn render_diff_preview(diff: &str, lines: &mut Vec<Line>, max_diff_lines: usize) {
    let gutter = "   │ ";
    let bg = Style::new().bg(Color::Rgb(30, 35, 50));

    for line in diff.lines().take(max_diff_lines) {
        let (prefix, style) = if line.starts_with("+++") || line.starts_with("---") {
            ("", Style::new().fg(Color::Rgb(140, 145, 160)).bold())
        } else if line.starts_with('+') {
            (
                "",
                Style::new()
                    .fg(Color::Rgb(80, 200, 120))
                    .bg(Color::Rgb(20, 40, 25)),
            )
        } else if line.starts_with('-') {
            (
                "",
                Style::new()
                    .fg(Color::Rgb(220, 80, 80))
                    .bg(Color::Rgb(50, 20, 20)),
            )
        } else if line.starts_with("@@") {
            ("", Style::new().fg(Color::Rgb(100, 140, 220)))
        } else {
            ("", Style::new().fg(Color::Rgb(140, 145, 160)))
        };
        let _ = prefix;
        let truncated = if line.chars().count() > 100 {
            let t: String = line.chars().take(97).collect();
            format!("{t}…")
        } else {
            line.to_string()
        };
        lines.push(
            Line::from(vec![
                Span::styled(gutter, Style::new().fg(Color::Rgb(55, 60, 75))),
                Span::styled(truncated, style),
            ])
            .style(bg),
        );
    }
    let total = diff.lines().count();
    if total > max_diff_lines {
        lines.push(
            Line::from(vec![
                Span::styled(gutter, Style::new().fg(Color::Rgb(55, 60, 75))),
                Span::styled(
                    format!("…{} more lines", total - max_diff_lines),
                    Style::new().fg(Color::DarkGray),
                ),
            ])
            .style(bg),
        );
    }
}

fn render_content_preview(
    blocks: &[ContentBlock],
    lines: &mut Vec<Line>,
    _width: usize,
    max_lines: usize,
) {
    let gutter = "   │   ";
    let bg = Style::new().bg(Color::Rgb(30, 35, 50));

    for block in blocks {
        match block {
            ContentBlock::Text { text } => {
                let limit = max_lines;
                let total_lines = text.lines().count();
                for (li, line) in text.lines().take(limit).enumerate() {
                    let truncated = if line.chars().count() > 100 {
                        let t: String = line.chars().take(97).collect();
                        format!("{}…", t)
                    } else {
                        line.to_string()
                    };
                    lines.push(
                        Line::from(vec![
                            Span::styled(gutter, Style::new().fg(Color::Rgb(55, 60, 75))),
                            Span::styled(truncated, Style::new().fg(Color::Rgb(170, 175, 190))),
                        ])
                        .style(bg),
                    );
                    if li == limit - 1 && total_lines > limit {
                        lines.push(
                            Line::from(vec![
                                Span::styled(gutter, Style::new().fg(Color::Rgb(55, 60, 75))),
                                Span::styled("…more", Style::new().fg(Color::DarkGray)),
                            ])
                            .style(bg),
                        );
                    }
                }
            }
            ContentBlock::Code { code, language, .. } => {
                let lang = language.as_deref().unwrap_or("");
                let code_limit = max_lines.saturating_sub(2);
                lines.push(
                    Line::from(vec![
                        Span::styled(gutter, Style::new().fg(Color::Rgb(55, 60, 75))),
                        Span::styled(format!("```{}", lang), Style::new().fg(Color::DarkGray)),
                    ])
                    .style(bg),
                );
                for line in code.lines().take(code_limit) {
                    let truncated = if line.chars().count() > 100 {
                        let t: String = line.chars().take(97).collect();
                        format!("{}…", t)
                    } else {
                        line.to_string()
                    };
                    lines.push(
                        Line::from(vec![
                            Span::styled(gutter, Style::new().fg(Color::Rgb(55, 60, 75))),
                            Span::styled(truncated, Style::new().fg(Color::Rgb(130, 200, 130))),
                        ])
                        .style(bg),
                    );
                }
                lines.push(
                    Line::from(vec![
                        Span::styled(gutter, Style::new().fg(Color::Rgb(55, 60, 75))),
                        Span::styled("```", Style::new().fg(Color::DarkGray)),
                    ])
                    .style(bg),
                );
            }
            ContentBlock::Json { data } => {
                let formatted =
                    serde_json::to_string_pretty(data).unwrap_or_else(|_| format!("{:?}", data));
                for line in formatted.lines().take(max_lines) {
                    lines.push(
                        Line::from(vec![
                            Span::styled(gutter, Style::new().fg(Color::Rgb(55, 60, 75))),
                            Span::styled(
                                line.to_string(),
                                Style::new().fg(Color::Rgb(220, 200, 120)),
                            ),
                        ])
                        .style(bg),
                    );
                }
            }
            _ => {}
        }
    }
}

/// Map event type to a high-level "role" for turn boundary detection.
fn event_role(event_type: &EventType) -> &'static str {
    match event_type {
        EventType::UserMessage => "user",
        EventType::AgentMessage | EventType::Thinking => "agent",
        EventType::ToolCall { .. }
        | EventType::ToolResult { .. }
        | EventType::FileRead { .. }
        | EventType::CodeSearch { .. }
        | EventType::FileSearch { .. }
        | EventType::FileEdit { .. }
        | EventType::FileCreate { .. }
        | EventType::FileDelete { .. }
        | EventType::ShellCommand { .. }
        | EventType::WebSearch { .. }
        | EventType::WebFetch { .. }
        | EventType::ImageGenerate { .. }
        | EventType::VideoGenerate { .. }
        | EventType::AudioGenerate { .. } => "agent",
        EventType::SystemMessage => "system",
        EventType::TaskStart { .. } | EventType::TaskEnd { .. } => "task",
        EventType::Custom { .. } => "other",
        _ => "other",
    }
}

