use ratatui::prelude::*;
use ratatui::widgets::{Block, Clear, Padding, Paragraph};

pub fn render(frame: &mut Frame, area: Rect) {
    // Center the help overlay
    let popup_width = 60u16.min(area.width.saturating_sub(4));
    let popup_height = 30u16.min(area.height.saturating_sub(4));
    let x = (area.width.saturating_sub(popup_width)) / 2;
    let y = (area.height.saturating_sub(popup_height)) / 2;
    let popup_area = Rect::new(x, y, popup_width, popup_height);

    frame.render_widget(Clear, popup_area);

    let block = Block::bordered()
        .title(" Keyboard Shortcuts ")
        .border_style(Style::new().fg(Color::Rgb(100, 180, 240)))
        .padding(Padding::new(2, 2, 1, 1));
    let inner = block.inner(popup_area);
    frame.render_widget(block, popup_area);

    let key_style = Style::new().fg(Color::Rgb(220, 180, 60)).bold();
    let desc_style = Style::new().fg(Color::Rgb(170, 175, 190));
    let header_style = Style::new().fg(Color::Rgb(100, 180, 240)).bold();

    let lines = vec![
        Line::from(Span::styled("── Global ──", header_style)),
        Line::from(vec![
            Span::styled("  1/2/3/4   ", key_style),
            Span::styled("Switch tabs (Sessions/Teams/Invitations/Settings)", desc_style),
        ]),
        Line::from(vec![
            Span::styled("  ?         ", key_style),
            Span::styled("Toggle this help", desc_style),
        ]),
        Line::from(vec![
            Span::styled("  q         ", key_style),
            Span::styled("Quit", desc_style),
        ]),
        Line::raw(""),
        Line::from(Span::styled("── Session List ──", header_style)),
        Line::from(vec![
            Span::styled("  j/k       ", key_style),
            Span::styled("Navigate up/down", desc_style),
        ]),
        Line::from(vec![
            Span::styled("  g/G       ", key_style),
            Span::styled("Jump to first/last", desc_style),
        ]),
