    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            ViewMode::Local => write!(f, "Local"),
            ViewMode::Team(t) => write!(f, "Team: {t}"),
            ViewMode::Repo(r) => write!(f, "Repo: {r}"),
        }
    }
}

